#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 16
#endif

int device_id_inuse = 0;
int platform_id_inuse = 0;

extern int kernel_gpu_opencl_wrapper(int xmax,
                                     int workload,
                                     fp ***y,
                                     fp **x,
                                     fp **params,
                                     fp *com);

static int isInteger_local(char *str){
    if (*str == '\0'){
        return 0;
    }
    for(; *str != '\0'; str++){
        if (*str < 48 || *str > 57){
            return 0;
        }
    }
    return 1;
}

static void read_file_local(char *filename,
                            fp *input,
                            int data_rows,
                            int data_cols,
                            int major){

    FILE *fid;
    int i, j;
    fp temp;

    fid = fopen(filename, "r");
    if( fid == NULL ){
        printf("The file was not opened for reading\n");
        fflush(0);
        return;
    }

    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%f", &temp);
                input[i*data_cols+j] = (fp)temp;
            }
        }
    }
    else{
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fscanf(fid, "%f", &temp);
                input[j*data_rows+i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

int main(int argc, char *argv []){

    int cur_arg;
    int xmax = 0;
    int workload = 1;
    char *data_dir = ".";

    if(argc>3){
        for(cur_arg=1; cur_arg<argc; cur_arg++){

            if(strcmp(argv[cur_arg], "-time")==0){
                if(argc>=cur_arg+1){
                    if(isInteger_local(argv[cur_arg+1])==1){
                        xmax = atoi(argv[cur_arg+1]);
                        if(xmax<0){
                            printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
                            return 0;
                        }
                        cur_arg = cur_arg+1;
                    }
                    else{
                        printf("RROR: Value to -time argument in not a number\n");
                        return 0;
                    }
                }
                else{
                    printf("ERROR: Missing value to -time argument\n");
                    return 0;
                }
            }
            else if(strcmp(argv[cur_arg], "-p")==0) {
                if(argc>=cur_arg+1){
                    if(isInteger_local(argv[cur_arg+1])==1) {
                        platform_id_inuse = atoi(argv[cur_arg+1]);
                        cur_arg = cur_arg+1;
                    }
                }
            }
            else if(strcmp(argv[cur_arg], "-d")==0) {
                if(argc>=cur_arg+1){
                    if(isInteger_local(argv[cur_arg+1])==1) {
                        device_id_inuse = atoi(argv[cur_arg+1]);
                        cur_arg = cur_arg+1;
                    }
                }
            }
            else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (argc >= cur_arg+1) {
                    data_dir = argv[cur_arg+1];
                    cur_arg++;
                }
            }
            else{
                printf("ERROR: Unknown argument\n");
                return 0;
            }
        }
    }
    else{
        printf("Provide time argument, example: -time 100");
        return 0;
    }

    if(workload == 1){

        int i, j;

        long long memory;
        memory = workload*(xmax+1)*EQUATIONS*4;
        if(memory>1000000000){
            printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
            return 0;
        }

        fp ***y;
        y = (fp ***) malloc(workload * sizeof(fp **));
        for(i=0; i<workload; i++){
            y[i] = (fp**)malloc((1+xmax) * sizeof(fp*));
            for(j=0; j<(1+xmax); j++){
                y[i][j] = (fp *) malloc(EQUATIONS * sizeof(fp));
            }
        }

        fp **x;
        x = (fp **) malloc(workload * sizeof(fp *));
        for (i=0; i<workload; i++){
            x[i] = (fp *)malloc((1+xmax) * sizeof(fp));
        }

        fp **params;
        params = (fp **) malloc(workload * sizeof(fp *));
        for (i=0; i<workload; i++){
            params[i] = (fp *)malloc(PARAMETERS * sizeof(fp));
        }

        fp *com;
        com = (fp*)malloc(3 * sizeof(fp));

        char y_file[4096];
        sprintf(y_file, "%s/%s", data_dir, "y.txt");
        for(i=0; i<workload; i++){
            read_file_local(y_file,
                            y[i][0],
                            EQUATIONS,
                            1,
                            0);
        }

        char params_file[4096];
        sprintf(params_file, "%s/%s", data_dir, "params.txt");
        for(i=0; i<workload; i++){
            read_file_local(params_file,
                            params[i],
                            PARAMETERS,
                            1,
                            0);
        }

        kernel_gpu_opencl_wrapper(xmax,
                                  workload,
                                  y,
                                  x,
                                  params,
                                  com);

        FILE *pFile;
        pFile = fopen("output.txt","w");
        if (pFile==NULL){
            fputs("fopen example",pFile);
            return -1;
        }

        int k;
        for(i=0; i<workload; i++){
            fprintf(pFile, "WORKLOAD %d:\n", i);
            for(j=0; j<(xmax+1); j++){
                fprintf(pFile, "\tTIME %d:\n", j);
                for(k=0; k<EQUATIONS; k++){
                    fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
                }
            }
        }

        fclose(pFile);

        for (i=0; i<workload; i++){
            for (j=0; j<(1+xmax); j++){
                free(y[i][j]);
            }
            free(y[i]);
        }
        free(y);

        for (i=0; i<workload; i++){
            free(x[i]);
        }
        free(x);

        for (i=0; i<workload; i++){
            free(params[i]);
        }
        free(params);

        free(com);
    }

    return 0;
}
